use std::collections::HashMap;

struct AppConfig {
    api_key: String,
    database_url: String,
    is_production: bool,
}

fn load_config(profile: &str) -> Result<AppConfig, String> {
    match profile {
        "test" => Ok(AppConfig {
            api_key: "test_key".to_string(),
            database_url: "sqlite://test.db".to_string(),
            is_production: false,
        }),
        "ci" => Ok(AppConfig {
            api_key: "ci_secret".to_string(),
            database_url: "postgres://user:pass@localhost/ci".to_string(),
            is_production: false,
        }),
        "release" => { 
            if std::env::var("APP_JWT_SECRET").is_err() {
                return Err("Missing required environment variable APP_JWT_SECRET for release mode".to_string());
            }
            Ok(AppConfig {
                api_key: std::env::var("APP_JWT_SECRET").unwrap(),
                database_url: "postgres://user:pass@prod.db".to_string(),
                is_production: true,
            })
        },
        _ => Err(format!("Unknown profile specified: {}", profile)),
    }
}

fn main() -> Result<(), String> {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 2 {
        println!("Usage: cargo run -- <profile>");
        return Ok(()) 
    }

    let profile_to_run = &args[1];
    println!("Loading configuration for profile: {}", profile_to_run);

    match load_config(profile_to_run) {
        Ok(config) => {
            if config.is_production {
                println!("SUCCESS: Running in PRODUCTION mode. API Key loaded.");
            } else {
                println!("SUCCESS: Loaded for non-production profile ({}). DB URL: {}", profile_to_run, config.database_url);
            }
        },
        Err(e) => {
            eprintln!("ERROR: Failed to load application configuration: {}", e);
            std::process::exit(1);
        }
    }

    Ok(())
}

use std::fs::File;
use std::io::{self, Write};

struct SimulationConfig {
    gravity: (f32, f32),
    damping: f32,
}

fn load_default_config() -> io::Result<SimulationConfig> {
    Ok(SimulationConfig { gravity: (0.0, -9.81), damping: 0.1 })
}

fn run_simulation(config: SimulationConfig, log_level: &str) -> io::Result<()> {
    println!("Starting simulation with gravity {:?}", config.gravity);

    match log_level {
        "debug" => {
            let mut log_file = File::create("debug_log.txt")?;
            writeln!(log_file, "Simulation started at runtime.")?;
            write!(log_file, "Damping factor is {}n", config.damping)?;
        },
        "release" => {
            println!("Running optimized release build.");
        },
        _ => {
            println!("Using default logging level.");
        }
    }

    if log_level != "skip_io" {
        let mut output = io::stdout();
        writeln!(output, "Simulation finished successfully!")?;
    }

    Ok(())
}

fn main() -> io::Result<()> {
    let base_config = load_default_config()?;

    #[cfg(feature = "debug_build")]
    { 
        run_simulation(base_config, "debug")?;
    }

    #[cfg(feature = "optimized_release")]
    { 
        run_simulation(base_config, "release")?;
    }

    #[cfg(not(any(feature = "debug_build", feature = "optimized_release")))]
    { 
        run_simulation(base_config, "skip_io")?;
    }

    Ok(())
}

