use std::collections::BTreeMap;
use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, Deserialize, Serialize)]
struct Record {
    key: String,
    value: String,
}

struct LsmTreeBackend {
    storage: BTreeMap<String, Record>,
}

impl LsmTreeBackend {
    fn new() -> Self {
        LsmTreeBackend {
            storage: BTreeMap::new(),
        }
    }

    fn merge_batch(&mut self, batch: Vec<Record>) -> Result<(), String> {
        for record in batch {
            if let Some(existing) = self.storage.get(&record.key) {
                let merged_value = format!("{}: {}", existing.value, record.value);
                self.storage.insert(record.key.clone(), Record { key: record.key, value: merged_value });
            } else {
                self.storage.insert(record.key.clone(), record);
            }
        }
        Ok(())
    }

    fn get_all_records(&self) -> &BTreeMap<String, Record> {
        &self.storage
    }
}

fn main() {
    let mut backend = LsmTreeBackend::new();

    let batch1 = vec![
        Record { key: "user_id".to_string(), value: "initial_data".to_string() },
        Record { key: "session_key".to_string(), value: "abc".to_string() }
    ];
    backend.merge_batch(batch1).expect("Failed to merge batch 1");

    let batch2 = vec![
        Record { key: "user_id".to_string(), value: "update_data".to_string() },
        Record { key: "new_key".to_string(), value: "xyz".to_string() }
    ];
    backend.merge_batch(batch2).expect("Failed to merge batch 2");

    println!("n--- Final Storage Contents ---n");
    for (key, record) in backend.get_all_records() {
        println!("Key: \"{}\", \"Value: \"{}\"", key, record.value);
    }
}

use std::collections::HashMap;
use std::fs;

struct ConfigManager {
    base_path: String,
    profiles: HashMap<String, String>,
}

impl ConfigManager {
    fn new(base_path: &str) -> Self {
        let mut profiles = HashMap::new();
        profiles.insert("dev".to_string(), format!("{}/dev", base_path));
        profiles.insert("staging".to_string(), format!("{}/staging", base_path));
        profiles.insert("prod".to_string(), format!("{}/prod", base_path));
        ConfigManager {
            base_path: base_path.to_string(),
            profiles:
                profiles.into_iter().map(|(k, v)| (k, v)).collect(),
        }
    }

    fn get_target_dir(&self, profile: &str) -> Option<String> {
        match profile {
            "dev" => self.profiles.get("dev").cloned(),
            "staging" => self.profiles.get("staging").cloned(),
            "prod" => self.profiles.get("prod").cloned(),
            _ => None,
        }
    }

    fn apply_symlinks(&self, profile: &str) -> Result<(), std::io::Error> {
        let target = match self.get_target_dir(profile) {
            Some(path) => path, 
            None => return Err(std::io::Error::new(std::io::ErrorKind::InvalidInput, "Unknown profile"))
        };

        println!("Targeting deployment profile: {}", profile);
        println!("Root directory resolved to: {}", target);

        if !fs::create_dir_all(&target).is_ok() {
            return Err(std::io::Error::last_os_error());
        }

        let source = format!("~/dotfiles/source_{}", profile);
        println!("Simulating link from {} to {}", source, target);

        Ok(())
    }
}

fn main() {
    let base_dir = "/etc/managed_configs";
    let manager = ConfigManager::new(base_dir);

    if let Err(e) = manager.apply_symlinks("staging") {
        eprintln!("Failed to apply configuration for staging: {}", e);
    }
}
